const BASE_URL = 'http://localhost:8080/api';

const getHeaders = () => {
  const token = localStorage.getItem('token');
  return {
    'Content-Type': 'application/json',
    ...(token && { Authorization: `Bearer ${token}` }),
  };
};

// Your Spring Boot wraps everything in ApiResponse<T> { message, data, success }
// This unwraps it automatically
const unwrap = (json) => {
  if (json && typeof json === 'object' && 'data' in json) return json.data;
  return json;
};

const request = async (method, path, body = null) => {
  const url = `${BASE_URL}${path}`;
  console.log(`[API] ${method} ${url}`, body ?? '');

  let res;
  try {
    res = await fetch(url, {
      method,
      headers: getHeaders(),
      ...(body !== null && { body: JSON.stringify(body) }),
    });
  } catch (networkErr) {
    console.error('[API] Network error:', networkErr);
    throw new Error('Cannot connect to server. Is Spring Boot running on port 8080?');
  }

  console.log(`[API] ${res.status} <- ${url}`);

  if (res.status === 401) {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    window.location.href = '/login';
    throw new Error('Session expired. Please login again.');
  }

  if (!res.ok) {
    let errMsg = `Server error (${res.status})`;
    try {
      const errBody = await res.json();
      errMsg = errBody.message || errBody.error || errMsg;
    } catch {
      try { errMsg = await res.text() || errMsg; } catch {}
    }
    console.error(`[API] Error ${res.status}:`, errMsg);
    throw new Error(errMsg);
  }

  if (res.status === 204) return null;

  try {
    const json = await res.json();
    return unwrap(json);
  } catch {
    return null;
  }
};

const getStoredUser = () => {
  try { return JSON.parse(localStorage.getItem('user')); } catch { return null; }
};

// AUTH
export const authAPI = {
  login: (data) => request('POST', '/auth/login', data),
  register: (data) => request('POST', '/auth/register', data),
  checkEmail: async (email) => {
    try {
      return await request('GET', `/auth/check-email?email=${encodeURIComponent(email)}`);
    } catch {
      return { exists: false };
    }
  },
};

// EVENTS
// Your endpoints: GET /api/events, GET /api/events/filter, GET /api/events/organiser/{id}
// POST /api/events, PUT /api/events/{id}, DELETE /api/events/{id}
export const eventAPI = {
  getAll: (params = {}) => {
    const hasFilters = Object.values(params).some(v => v);
    const q = new URLSearchParams(
      Object.fromEntries(Object.entries(params).filter(([, v]) => v))
    ).toString();
    if (hasFilters) return request('GET', `/events/filter?${q}`);
    return request('GET', '/events');
  },
  getById: (id) => request('GET', `/events/${id}`),
  getMyEvents: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return request('GET', `/events/organiser/${user.userId}`);
  },
  create: (data) => {
    const user = getStoredUser();
    return request('POST', '/events', { ...data, organiserId: user?.userId });
  },
  update: (id, data) => request('PUT', `/events/${id}`, data),
  delete: (id) => request('DELETE', `/events/${id}`),
  search: (name) => request('GET', `/events/search?name=${encodeURIComponent(name)}`),
};

// SHOW SLOTS
export const slotAPI = {
  getByEvent: (eventId) => request('GET', `/show-slots/event/${eventId}`),
  create: (data) => request('POST', '/show-slots', data),
  update: (id, data) => request('PUT', `/show-slots/${id}`, data),
  delete: (id) => request('DELETE', `/show-slots/${id}`),
};

// LOCATIONS
export const locationAPI = {
  getAll: () => request('GET', '/locations'),
  getById: (id) => request('GET', `/locations/${id}`),
  create: (data) => request('POST', '/locations', data),
};

// SEATS
export const seatAPI = {
  getBySlot: (slotId) => request('GET', `/seat-slots/slot/${slotId}`),
  getByLocation: (locationId) => request('GET', `/seats/location/${locationId}`),
};

// RESERVATIONS
export const reservationAPI = {
  create: (data) => request('POST', '/reservations', data),
  getMyReservations: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return request('GET', `/reservations/user/${user.userId}`);
  },
  getById: (id) => request('GET', `/reservations/${id}`),
  getAll: () => request('GET', '/reservations'),
  cancel: (id, reason) => request('POST', `/reservations/${id}/cancel`, { reason }),
};

// TRANSACTIONS
export const transactionAPI = {
  processPayment: (data) => request('POST', '/transactions', data),
  getMyTransactions: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return request('GET', `/transactions/user/${user.userId}`);
  },
  getAll: () => request('GET', '/transactions'),
  getByReservation: (resId) => request('GET', `/transactions/reservation/${resId}`),
};

// NOTIFICATIONS
export const notificationAPI = {
  getMyNotifications: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return request('GET', `/notifications/user/${user.userId}`);
  },
  markRead: (id) => request('PUT', `/notifications/${id}/read`),
  sendBulk: (data) => request('POST', '/notifications/send-bulk', data),
  sendReminders: (slotId) => request('POST', `/notifications/remind/${slotId}`),
};
